SELECT [def01-ANALISIVENDUTO-PIVOT].[Season Code] AS Stagione, [def01-ANALISIVENDUTO-PIVOT].[Trademark Code] AS Marchio, [def01-ANALISIVENDUTO-PIVOT].[Salesperson Code] AS CodiceAgente, [def01-ANALISIVENDUTO-PIVOT].Salesperson AS Agente, [def01-ANALISIVENDUTO-PIVOT].CustomerCode AS CodiceCliente, [def01-ANALISIVENDUTO-PIVOT].CustomerName AS Cliente, [def01-ANALISIVENDUTO-PIVOT].[Line Code] AS Linea, [def01-ANALISIVENDUTO-PIVOT].Article AS Articolo, [def01-ANALISIVENDUTO-PIVOT].ColorCode AS CodiceColore, [def01-ANALISIVENDUTO-PIVOT].Color AS Colore, Sum(IIf([delete reason]='art',[pairsquantity],0)) AS PaiaAnnullate, Sum(IIf([delete reason]='art',[salesvalue],0)) AS ValoreAnnullato, Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,[pairsquantity],0)) AS PaiaConfermate, Sum(IIf([delete reason]='' Or IsNull([delete reason])=True,[salesvalue],0)) AS ValoreConfermato
FROM [def01-ANALISIVENDUTO-PIVOT]
GROUP BY [def01-ANALISIVENDUTO-PIVOT].[Season Code], [def01-ANALISIVENDUTO-PIVOT].[Trademark Code], [def01-ANALISIVENDUTO-PIVOT].[Salesperson Code], [def01-ANALISIVENDUTO-PIVOT].Salesperson, [def01-ANALISIVENDUTO-PIVOT].CustomerCode, [def01-ANALISIVENDUTO-PIVOT].CustomerName, [def01-ANALISIVENDUTO-PIVOT].[Line Code], [def01-ANALISIVENDUTO-PIVOT].Article, [def01-ANALISIVENDUTO-PIVOT].ColorCode, [def01-ANALISIVENDUTO-PIVOT].Color;

